#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
int a[100010],b[100010],c[100010],op[100010];
long long d[100010],f[100010];
vector<pair<int,int>> mp[100010],mp1[100010];
long long dfs(int x)
{
    if(d[x]!=-1)
    {
        return d[x];
    }
    d[x]=(op[x]==2?c[x]:1);
    long long sum=1;
    for(int i=mp[x].size()-1;i>=0;i--)
    {
        int v=mp[x][i].first;
        mp[x][i].second=sum;
        d[x]=d[x]*dfs(v)%mod;
        sum=sum*d[v]%mod;
    }
    return d[x];
}
long long dfs2(int x)
{
    if(f[x]!=-1)
    {
        return f[x];
    }
    f[x]=0;
    for(auto i:mp1[x])
    {
        int v=i.first,val=i.second;
        f[x]=(f[x]+val*dfs2(v)%mod)%mod;
    }
    return f[x];
}
int main()
{
    int n,m,q;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&op[i]);
        if(op[i]==1)
        {
            scanf("%d%d",&b[i],&c[i]);
        }
        else if(op[i]==2)
        {
            scanf("%d",&c[i]);
        }
        else
        {
            int t;
            scanf("%d",&t);
            while(t--)
            {
                int v;
                scanf("%d",&v);
                mp[i].push_back({v,0});
            }
        }
    }
    scanf("%d",&q);
    while(q--)
    {
        int v;
        scanf("%d",&v);
        mp[0].push_back({v,0});
    }
    memset(d,-1,sizeof(d));
    memset(f,-1,sizeof(f));
    dfs(0);
    f[0]=1;
    for(int i=1;i<=n;i++)
    {
        a[i]=a[i]*d[0]%mod;
    }
    for(int i=0;i<=m;i++)
    {
        for(auto j:mp[i])
        {
            mp1[j.first].push_back({i,j.second});
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(op[i]==1)
        {
            a[b[i]]=(a[b[i]]+dfs2(i)*c[i])%mod;
        }
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d ",a[i]);
    }
    return 0;
}
